"use client";

import { useState, useEffect } from "react";
import StatsPanel from "./StatsPanel";
import NodeCard from "./NodeCard";
import HuffmanTree from "./HuffmanTree";
import DifficultySelector from "./DifficultySelector";

export type HuffmanNode = {
  id: string;
  label: string;
  value: number;
  left?: HuffmanNode;
  right?: HuffmanNode;
  isLeaf?: boolean;
};

export default function HuffmanGame() {
  const [nodes, setNodes] = useState<HuffmanNode[]>([]);
  const [root, setRoot] = useState<HuffmanNode | null>(null);
  const [steps, setSteps] = useState(0);
  const [errors, setErrors] = useState(0);
  const [elapsed, setElapsed] = useState(0);
  const [difficulty, setDifficulty] = useState<"easy" | "medium" | "hard">("easy");
  const [started, setStarted] = useState(false);
  const [finished, setFinished] = useState(false);
  const [message, setMessage] = useState("Clique sur Commencer pour jouer.");

  // Timer
  useEffect(() => {
    if (!started || finished) return;
    const interval = setInterval(() => setElapsed((t) => t + 1), 1000);
    return () => clearInterval(interval);
  }, [started, finished]);

  // Générer les symboles
  function startGame() {
    const count = difficulty === "easy" ? 4 : difficulty === "medium" ? 6 : 8;
    const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    const list: HuffmanNode[] = [];

    for (let i = 0; i < count; i++) {
      const freq = Math.floor(Math.random() * 40) + 5;
      list.push({
        id: alphabet[i],
        label: alphabet[i],
        value: freq,
        isLeaf: true,
      });
    }

    setNodes(list.sort((a, b) => a.value - b.value));
    setRoot(null);
    setSteps(0);
    setErrors(0);
    setElapsed(0);
    setStarted(true);
    setFinished(false);
    setMessage("Fusionne les deux plus petites valeurs.");
  }

  // Vérification fusion
  function combine(a: HuffmanNode, b: HuffmanNode) {
    const sorted = [...nodes].sort((x, y) => x.value - y.value);
    const s1 = sorted[0];
    const s2 = sorted[1];

    const valid =
      (a.value === s1.value && b.value === s2.value) ||
      (b.value === s1.value && a.value === s2.value);

    if (!valid) {
      setErrors((e) => e + 1);
      setMessage("❌ Mauvaise fusion : choisis les deux plus petites valeurs.");
      return;
    }

    const newNode: HuffmanNode = {
      id: a.id + b.id,
      label: `${a.label}+${b.label}`,
      value: a.value + b.value,
      left: a,
      right: b,
    };

    const updated = nodes
      .filter((n) => n.id !== a.id && n.id !== b.id)
      .concat(newNode)
      .sort((x, y) => x.value - y.value);

    setNodes(updated);
    setSteps((s) => s + 1);
    setMessage("✔ Bonne fusion ! Continue.");

    if (updated.length === 1) {
      setFinished(true);
      setRoot(newNode);
      setMessage("🎉 Arbre de Huffman complété !");
    }
  }

  function handleDrop(e: any, source: HuffmanNode) {
    const el = document.elementFromPoint(e.clientX, e.clientY);
    if (!el) return;

    const targetEl = el.closest("[data-node-id]") as HTMLElement | null;
    const targetId = targetEl?.dataset.nodeId;
    if (!targetId || targetId === source.id) return;

    const target = nodes.find((n) => n.id === targetId);
    if (target) combine(source, target);
  }

  const score = Math.max(0, 1000 - steps * 25 - errors * 50 - elapsed * 2);
  const timeFormatted = `${Math.floor(elapsed / 60)}:${String(elapsed % 60).padStart(2, "0")}`;

  return (
    <div className="space-y-8">

      {/* Header */}
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <div>
          <h1 className="text-4xl font-bold">Jeu : Arbre de Huffman</h1>
          <p className="text-white/70 text-sm">{message}</p>
        </div>

        <div className="flex gap-3">
          <DifficultySelector
            difficulty={difficulty}
            setDifficulty={setDifficulty}
            disabled={started && !finished}
          />

          <button
            onClick={startGame}
            className="px-4 py-2 rounded-xl bg-white text-black font-bold shadow-lg"
          >
            {started ? "Recommencer" : "Commencer"}
          </button>
        </div>
      </div>

      {/* Stats */}
      {started && (
        <StatsPanel
          time={timeFormatted}
          score={score}
          steps={steps}
          errors={errors}
        />
      )}

      {/* Zone du jeu */}
      <div className="grid lg:grid-cols-2 gap-8">

        {/* Nœuds */}
        <div className="bg-white/5 border border-white/10 rounded-3xl p-6">
          <h2 className="text-xl font-semibold mb-4">Nœuds</h2>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
            {nodes.map((node) => (
              <NodeCard key={node.id} node={node} onDrop={handleDrop} />
            ))}
          </div>
        </div>

        {/* Arbre final */}
        <div className="bg-white/5 border border-white/10 rounded-3xl p-6">
          <h2 className="text-xl font-semibold mb-4">Arbre de Huffman</h2>
          <HuffmanTree root={root} />
        </div>
      </div>

      {finished && (
        <div className="mt-6 p-4 rounded-xl bg-emerald-500/20 border border-emerald-300/40">
          🎉 Bravo ! Score final : <b>{score}</b>
        </div>
      )}
    </div>
  );
}
